x_424426_devops_context_menu_item.client_script:
/* global $context, g_ck, URLSearchParams, navigator, g_form, fetch, document, getComputedStyle */
/* eslint no-undef: "error" */
(async function ($context) {
	let gmf;
	const openInWindow = navigator.userAgent.indexOf('Mac OS X') > -1 ? $context.event.metaKey : $context.event.ctrlKey;
	let table = g_form.getTableName();
	if (table == 'ni') table = 'sc_req_item';

	g_form.addInfoMessage('Reference:<br><span id="devops_references_result">Loading ...</span>');
	var resultTarget = document.getElementById('devops_references_result');

	const tables = [];
	for (let currentTable = table; currentTable; ) {
		const request = await fetch('/api/now/table/sys_db_object?' + new URLSearchParams({
			sysparm_query: 'name=' + currentTable,
			sysparm_fields: 'super_class.name',
			sysparm_limit: 1
		}), {
			headers: {
				'X-UserToken': g_ck
			}
		});
		const result = (await request.json()).result?.at(0);
		if (!result) {
			g_form.addErrorMessage('Table ' + currentTable + ' not found in tables');
			return;
		}

		tables.push(currentTable);
		currentTable = result['super_class.name'];
	}

	let message = 'References:';
	if (tables.length) {
		// NOTE: does not yet cover document_id fields!
		const request = await fetch('/api/now/table/sys_dictionary?' + new URLSearchParams({
			sysparm_query: 'sys_class_name=sys_dictionary^internal_type=reference^ORinternal_type=list'
				+ '^referenceIN' + tables,
			sysparm_fields: 'name,element,internal_type.name'
		}), {
			headers: {
				'X-UserToken': g_ck
			}
		});

		const sysId = g_form.getUniqueValue();
		const queries = {};
		for (const field of await (await request.json()).result) {
			if (field['internal_type.name'] == 'reference') {
				(queries[field.name] ??= []).push(field.element + '=' + sysId);
			} else {
				(queries[field.name] ??= []).push(field.element + 'LIKE' + sysId);
			}
		}

		const tableData = await (async () => {
			const request = await fetch('/api/now/table/sys_db_object?' + new URLSearchParams({
				sysparm_query: 'nameIN' + Object.keys(queries),
				sysparm_fields: 'label,name,scriptable_table'
			}), {
				headers: {
					'X-UserToken': g_ck
				}
			});

			const data = {};
			for (const {label, name, scriptable_table} of (await request.json()).result) {
				data[name] = {
					label,
					remote: scriptable_table == "true"
				};
			}

			return data;
		})();

		let resultTable = '';
		for (const [table, conds] of Object.entries(queries)) {
			resultTable += `
				<tr data-table=${table}>
					<td>${tableData[table].label}</td>
					<td>${table}</td>
					<td><a target="_blank" href="/${table}_list.do?sysparm_query=${conds.join('^OR')}">Open ➚</a></td>
					<td style="text-align: center"></td>
				</tr>`;
		}

		if (resultTable) {
			resultTarget.innerHTML = '<table style="background-color: rgba(255, 255, 255, 0);"><tr><th>Label</th><th>Table</th><th>Link</th><th>Results</th><tr>' + resultTable 
				+ '<tr><td colspan=4><a href="javascript:void(0)" id="devops_references_result_loader">Load Results</a></td></tr>'
			+ '</table>';

			var loader = resultTarget.querySelector('#devops_references_result_loader');
			loader.addEventListener('click', async function () {
				if (loader.hasAttribute('disabled')) {
					return;
				}

				loader.setAttribute('disabled', '');
				for (const td of resultTarget.querySelectorAll('tr[data-table] td:last-child')) {
					td.innerHTML = '';
				}

				for (const [table, conds] of Object.entries(queries)) {
					const node = resultTarget.querySelector('tr[data-table=' + table + '] td:last-child');
					if (tableData[table].remote) {
						// do not search remote tables
						node.innerHTML = '(remote)';
						continue;
					}

					node.innerHTML = await fetch('/api/now/stats/' + table + '?' + new URLSearchParams({
						sysparm_query: conds.join('^OR'),
						sysparm_count: 'true'
					}), {
						headers: {
							'X-UserToken': g_ck
						}
					}).then(response => response.json())
					.then(json => json.result ? json.result.stats.count : '?');
				}

				loader.removeAttribute('disabled');
			});

			var resultContainer = resultTarget.closest('div.outputmsg');
			var msgContainer = resultTarget.closest('div.outputmsg_container');
			if (resultContainer && msgContainer) {
				if (parseInt(getComputedStyle(msgContainer).height) < parseInt(getComputedStyle(resultContainer).height)) {
					msgContainer.style.maxHeight = '100%';
				}
			}
		}
	} else {
		resultTarget.innerHTML = '<br>Unable to detect table';
	}

})($context);
